import React, { useState, useEffect, useMemo } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import {
  Input,
  Select,
  SearchInput,
  addToast,
  utcToLocalInputValue,
  localInputToISOWithOffset,
} from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { tscdService } from '../../../services/tscd/tscdService';
import type { CreateFixedAssetDto } from '../../../services/tscd/models';
import { createAccountSearchConfig } from '../../../components/search';
import { ktService } from '../../../services/kt/ktService';
import { DocumentFormHeader } from '../../../components/layout';
import df from '../../../styles/documentForm.module.css';

const DEPRECIATION_METHODS = [
  { value: 'StraightLine', label: 'Đường thẳng' },
  { value: 'DecliningBalance', label: 'Giảm dần' },
];

const TscdFormPage: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const isNew = !id;
  const navigate = useNavigate();
  const dispatch = useAppDispatch();
  const accountSearchConfig = useMemo(() => createAccountSearchConfig(), []);

  const [name, setName] = useState('');
  const [categoryCode, setCategoryCode] = useState('');
  const [originalCost, setOriginalCost] = useState(0);
  const [usefulLifeMonths, setUsefulLifeMonths] = useState(60);
  const [depreciationMethod, setDepreciationMethod] = useState('StraightLine');
  const [accountCode, setAccountCode] = useState('211');
  const [accountName, setAccountName] = useState('');
  const [depreciationExpenseAccountCode, setDepreciationExpenseAccountCode] = useState('627');
  const [depreciationExpenseAccountName, setDepreciationExpenseAccountName] = useState('');
  const [accumDepreciationAccountCode, setAccumDepreciationAccountCode] = useState('214');
  const [accumDepreciationAccountName, setAccumDepreciationAccountName] = useState('');
  const [acquiredDate, setAcquiredDate] = useState(new Date().toISOString().slice(0, 10));
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    if (isNew) return;
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      tscdService.getAsset(id!)
        .then(a => {
          if (cancelled) return;
          setName(a.name);
          setCategoryCode(a.categoryCode);
          setOriginalCost(a.originalCost);
          setUsefulLifeMonths(a.usefulLifeMonths);
          setDepreciationMethod(a.depreciationMethod);
          setAcquiredDate(utcToLocalInputValue(a.acquiredDate));
          setAccountCode(a.accountCode ?? '211');
          setDepreciationExpenseAccountCode(a.depreciationAccountCode ?? '627');
          setAccumDepreciationAccountCode(a.accumDepreciationAccountCode ?? '214');
        })
        .catch(err => { if (!cancelled) dispatch(addToast({ message: err?.message ?? 'Lỗi tải TSCĐ', type: 'error' })); })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [id, isNew, dispatch]);

  useEffect(() => {
    if (!accountCode?.trim() && !depreciationExpenseAccountCode?.trim() && !accumDepreciationAccountCode?.trim()) return;
    let cancelled = false;
    const t = setTimeout(() => {
      ktService.getAccounts({ isActive: true, isDetail: true }).then(accs => {
        if (cancelled) return;
        const asset = accs.find(a => a.code === accountCode);
        const expense = accs.find(a => a.code === depreciationExpenseAccountCode);
        const accum = accs.find(a => a.code === accumDepreciationAccountCode);
        if (asset) setAccountName(asset.name);
        if (expense) setDepreciationExpenseAccountName(expense.name);
        if (accum) setAccumDepreciationAccountName(accum.name);
      });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [accountCode, depreciationExpenseAccountCode, accumDepreciationAccountCode, id]);

  const buildDto = (): CreateFixedAssetDto => ({
    name,
    categoryCode,
    originalCost: Number(originalCost),
    usefulLifeMonths: Number(usefulLifeMonths),
    depreciationMethod,
    accountCode,
    depreciationExpense: { accountCode: depreciationExpenseAccountCode },
    accumDepreciation: { accountCode: accumDepreciationAccountCode },
    acquiredDate: localInputToISOWithOffset(acquiredDate),
  });

  const handleSave = async () => {
    if (!name || !categoryCode) {
      dispatch(addToast({ message: 'Tên và loại TSCĐ là bắt buộc', type: 'error' }));
      return;
    }
    setSaving(true);
    try {
      if (isNew) {
        const created = await tscdService.createAsset(buildDto());
        dispatch(addToast({ message: 'Tạo TSCĐ thành công', type: 'success' }));
        navigate(`/tscd/${created.id}`);
      } else {
        await tscdService.updateAsset(id!, buildDto());
        dispatch(addToast({ message: 'Cập nhật thành công', type: 'success' }));
      }
    } catch (e: unknown) {
      dispatch(addToast({ message: e instanceof Error ? e.message : 'Lỗi lưu', type: 'error' }));
    } finally {
      setSaving(false);
    }
  };

  if (loading) return <div className={df.loading}>Đang tải...</div>;

  return (
    <div className={df.page}>
      <DocumentFormHeader
        onBack={() => navigate('/tscd/danh-sach')}
        title={isNew ? 'Thêm tài sản cố định' : `TSCĐ — ${name}`}
        isNew={isNew}
        saving={saving}
        saveLabel="Tạo TSCĐ"
        saveEditLabel="Lưu thay đổi"
        onSave={handleSave}
      />

      <div className={df.section}>
        <h2 className={df.sectionTitle}>Thông tin tài sản</h2>
        <div className={df.row4}>
          <div className={df.field}>
            <label className={df.label}>Tên TSCĐ *</label>
            <Input value={name} onChange={e => setName(e.target.value)} />
          </div>
          <div className={df.field}>
            <label className={df.label}>Mã loại *</label>
            <Input value={categoryCode} onChange={e => setCategoryCode(e.target.value)} />
          </div>
          <div className={df.field}>
            <label className={df.label}>Nguyên giá</label>
            <Input type="number" min={0} value={String(originalCost)} onChange={e => setOriginalCost(Number(e.target.value))} />
          </div>
          <div className={df.field}>
            <label className={df.label}>Thời gian KH (tháng)</label>
            <Input type="number" min={1} value={String(usefulLifeMonths)} onChange={e => setUsefulLifeMonths(Number(e.target.value))} />
          </div>
        </div>
        <div className={df.row4}>
          <div className={df.field}>
            <label className={df.label}>Phương pháp KH</label>
            <Select value={depreciationMethod} onChange={e => setDepreciationMethod(e.target.value)} options={DEPRECIATION_METHODS} />
          </div>
          <div className={df.field}>
            <label className={df.label}>Ngày mua</label>
            <Input type="date" value={acquiredDate} onChange={e => setAcquiredDate(e.target.value)} />
          </div>
          <div className={df.field} data-testid="tscd-field-accountCode">
            <label className={df.label}>TK TSCĐ</label>
            <SearchInput
              config={accountSearchConfig}
              value={accountCode}
              primaryDisplay={accountCode}
              secondaryDisplay={accountName}
              clearOnType
              onChange={a => {
                setAccountCode(a.code);
                setAccountName(a.name);
              }}
              onClear={() => {
                setAccountCode('');
                setAccountName('');
              }}
              showLabel={false}
              showSecondaryInput={false}
              placeholder="Mã hoặc tên TK..."
            />
          </div>
          <div className={df.field} data-testid="tscd-field-depreciationExpenseAccountCode">
            <label className={df.label}>TK chi phí KH</label>
            <SearchInput
              config={accountSearchConfig}
              value={depreciationExpenseAccountCode}
              primaryDisplay={depreciationExpenseAccountCode}
              secondaryDisplay={depreciationExpenseAccountName}
              clearOnType
              onChange={a => {
                setDepreciationExpenseAccountCode(a.code);
                setDepreciationExpenseAccountName(a.name);
              }}
              onClear={() => {
                setDepreciationExpenseAccountCode('');
                setDepreciationExpenseAccountName('');
              }}
              showLabel={false}
              showSecondaryInput={false}
              placeholder="Mã hoặc tên TK..."
            />
          </div>
        </div>
        <div className={df.row4}>
          <div className={df.field} data-testid="tscd-field-accumDepreciationAccountCode">
            <label className={df.label}>TK hao mòn lũy kế</label>
            <SearchInput
              config={accountSearchConfig}
              value={accumDepreciationAccountCode}
              primaryDisplay={accumDepreciationAccountCode}
              secondaryDisplay={accumDepreciationAccountName}
              clearOnType
              onChange={a => {
                setAccumDepreciationAccountCode(a.code);
                setAccumDepreciationAccountName(a.name);
              }}
              onClear={() => {
                setAccumDepreciationAccountCode('');
                setAccumDepreciationAccountName('');
              }}
              showLabel={false}
              showSecondaryInput={false}
              placeholder="Mã hoặc tên TK..."
            />
          </div>
        </div>
      </div>
    </div>
  );
};

export default TscdFormPage;
